#!/usr/bin/env node
/**
 * apply-canonical-gaps-final.js
 *
 * Apply all canonical gaps (pairs in canonical fingerprint but NOT in driver.compose.json)
 * to the right driver. Each pair has a driver hint in the cross-ref report.
 *
 * Strategy:
 * 1. Read .github/state/mfr-pid-cross-ref.json (generated by cross-ref-all-sources.js)
 * 2. For each (mfr, pid) pair in inCanonicalNotDriversList, find the hinted driver.
 * 3. Add the mfr to that driver's manufacturerName list.
 * 4. Skip if the mfr is already in the driver.
 *
 * Run: node tools/ci/apply-canonical-gaps-final.js [--dry]
 */
'use strict';

const fs = require('fs');
const path = require('path');

const REPO = path.join(__dirname, '..', '..');
const DRIVERS = path.join(REPO, 'drivers');
const REPORT = path.join(REPO, '.github/state/mfr-pid-cross-ref.json');

const dryRun = process.argv.includes('--dry');
const skipDrivers = new Set(
  process.argv.filter(a => a.startsWith('--skip-driver=')).map(a => a.replace('--skip-driver=', ''))
);
const skipDriversFile = path.join(REPO, 'tools/ci/apply-canonical-gaps-final.skip-drivers.json');
try {
  if (fs.existsSync(skipDriversFile)) {
    const json = JSON.parse(fs.readFileSync(skipDriversFile, 'utf8'));
    for (const d of json.drivers || []) skipDrivers.add(d);
  }
} catch {}

// Reject malformed mfrs (e.g. "_TZE" without a model suffix — these are artifacts)
const MALFORMED_MFR = /^(_\w+|_$)/;
const mfrIsValid = (m) => {
  if (!m) return false;
  // A valid Tuya mfr is _TZE###_xxxxxx or _TZ####_xxxxxx (10-20 chars, 3-digit or 4-digit series)
  return /^_(TZE\d{3}|TZE\d{4}|TZ\d{4}|TZE\d{3}C\d+)_[A-Za-z0-9]{4,}$/i.test(m);
};

if (!fs.existsSync(REPORT)) {
  console.error(`ERROR: cross-ref report not found at ${REPORT}`);
  console.error('Run: node tools/ci/cross-ref-all-sources.js');
  process.exit(1);
}

const report = JSON.parse(fs.readFileSync(REPORT, 'utf8'));
const gaps = report.inCanonicalNotDriversList || [];
console.log(`[1/3] Loaded ${gaps.length} canonical gaps from cross-ref report`);

if (gaps.length === 0) {
  console.log('[2/3] No gaps to apply. Exiting.');
  process.exit(0);
}

// Group by target driver (first in hint list)
const byDriver = new Map();
let rejectedMalformed = 0;
for (const g of gaps) {
  if (!mfrIsValid(g.mfr)) {
    rejectedMalformed++;
    continue;
  }
  const drv = (g.drivers && g.drivers[0]) || null;
  if (!drv) continue;
  if (!byDriver.has(drv)) byDriver.set(drv, []);
  byDriver.get(drv).push(g);
}
if (rejectedMalformed > 0) {
  console.log(`[2/3] Rejected ${rejectedMalformed} malformed mfr(s) (e.g. "_TZE" without model)`);
}
console.log(`[2/3] Grouped into ${byDriver.size} driver(s)`);

let totalAdded = 0;
let totalSkipped = 0;
const perDriver = [];

for (const [drvId, drvGaps] of byDriver) {
  if (skipDrivers.has(drvId)) {
    console.log(`  ⏭️  ${drvId}: SKIPPED (in skip list) — ${drvGaps.length} pairs not applied`);
    totalSkipped += drvGaps.length;
    continue;
  }
  const composePath = path.join(DRIVERS, drvId, 'driver.compose.json');
  if (!fs.existsSync(composePath)) {
    console.log(`  ⚠️ ${drvId}: no driver.compose.json — skipping ${drvGaps.length} pairs`);
    totalSkipped += drvGaps.length;
    continue;
  }
  let compose;
  try {
    compose = JSON.parse(fs.readFileSync(composePath, 'utf8'));
  } catch (e) {
    console.log(`  ❌ ${drvId}: JSON parse error: ${e.message}`);
    totalSkipped += drvGaps.length;
    continue;
  }
  if (!compose.zigbee) {
    console.log(`  ⚠️ ${drvId}: no zigbee block — skipping`);
    totalSkipped += drvGaps.length;
    continue;
  }
  if (!Array.isArray(compose.zigbee.manufacturerName)) {
    compose.zigbee.manufacturerName = [];
  }
  const before = new Set(compose.zigbee.manufacturerName.map(s => s.toUpperCase()));
  const added = [];
  for (const g of drvGaps) {
    if (!before.has(g.mfr.toUpperCase())) {
      compose.zigbee.manufacturerName.push(g.mfr);
      added.push(g.mfr);
      totalAdded++;
    } else {
      totalSkipped++;
    }
  }
  if (added.length > 0) {
    if (!dryRun) {
      // Stable order: sort the array (preserve original casing)
      const seen = new Set();
      const unique = [];
      for (const m of compose.zigbee.manufacturerName) {
        const u = m.toUpperCase();
        if (!seen.has(u)) { seen.add(u); unique.push(m); }
      }
      unique.sort();
      compose.zigbee.manufacturerName = unique;
      fs.writeFileSync(composePath, JSON.stringify(compose, null, 2) + '\n', 'utf8');
    }
    console.log(`  ✓ ${drvId}: +${added.length} mfr(s) — ${added.slice(0, 5).join(', ')}${added.length > 5 ? '...' : ''}`);
    perDriver.push({ drvId, added: added.length });
  } else {
    console.log(`  - ${drvId}: 0 new mfrs (all ${drvGaps.length} already present)`);
  }
}

console.log(`\n${dryRun ? '[DRY]' : '[DONE]'} ${totalAdded} mfrs added across ${perDriver.length} drivers, ${totalSkipped} skipped`);
